#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *A = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &A[i]);
        int *ans = (int*)malloc(N * sizeof(int));
        ans[N-1] = 1;
        for (int i = N-2; i >= 0; --i) {
            if (A[i] * A[i+1] < 0) ans[i] = ans[i+1] + 1;
            else ans[i] = 1;
        }
        for (int i = 0; i < N; ++i) {
            printf("%d", ans[i]);
            if (i + 1 < N) printf(" ");
        }
        printf("\n");
        free(A);
        free(ans);
    }
    return 0;
}

