import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        ans = [1] * N
        for i in range(N-2, -1, -1):
            if A[i] * A[i+1] < 0:
                ans[i] = ans[i+1] + 1
        out_lines.append(' '.join(map(str, ans)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

